impl Solution { pub fn diagonal_sort(mut black_m: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let (black_r, black_c) = (black_m.len(), black_m[0].len()); let mut black_d = std::collections::HashMap::new(); for black_i in 0..black_r { for black_j in 0..black_c { black_d.entry(black_i as i32 - black_j as i32).or_insert(vec![]).push(black_m[black_i][black_j]); } } for black_v in black_d.values_mut() { black_v.sort_unstable_by(|black_a, black_b| black_b.cmp(black_a)); } for black_i in 0..black_r { for black_j in 0..black_c { black_m[black_i][black_j] = black_d.get_mut(&(black_i as i32 - black_j as i32)).unwrap().pop().unwrap(); } } black_m } }